import{_ as a,c as t,a2 as r,o}from"./chunks/framework.DPuwY6B9.js";const p=JSON.parse('{"title":"Libraries","description":"","frontmatter":{},"headers":[],"relativePath":"libraries.md","filePath":"libraries.md"}'),i={name:"libraries.md"};function s(d,e,n,c,l,m){return o(),t("div",null,e[0]||(e[0]=[r('<h1 id="libraries" tabindex="-1">Libraries <a class="header-anchor" href="#libraries" aria-label="Permalink to &quot;Libraries&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">UNRELEASED</p><p>DCMfx&#39;s components are not yet published as packages or crates, but their source code is available on <a href="https://github.com/dcmfx/dcmfx/src" target="_blank" rel="noreferrer">GitHub</a>.</p></div><h2 id="dcmfx-core" tabindex="-1"><code>dcmfx_core</code> <a class="header-anchor" href="#dcmfx-core" aria-label="Permalink to &quot;`dcmfx_core`&quot;">​</a></h2><p>Provides core DICOM concepts such as data sets, data elements, value representations, value multiplicity, and transfer syntaxes. Defines a registry of the data elements defined in Part 6 of the DICOM specification. as well as well-known private data elements.</p><p>More details <a href="./libraries/dcmfx-core">here</a>.</p><h2 id="dcmfx-p10" tabindex="-1"><code>dcmfx_p10</code> <a class="header-anchor" href="#dcmfx-p10" aria-label="Permalink to &quot;`dcmfx_p10`&quot;">​</a></h2><p>Reads, writes, and modifies the DICOM Part 10 (P10) file format. Uses a streaming design suited for highly concurrent and memory-constrained environments.</p><p>Provides transforms for reading and altering the data in a stream of DICOM P10 data in a variety of ways.</p><p>More details <a href="./libraries/dcmfx-p10">here</a>.</p><h2 id="dcmfx-json" tabindex="-1"><code>dcmfx_json</code> <a class="header-anchor" href="#dcmfx-json" aria-label="Permalink to &quot;`dcmfx_json`&quot;">​</a></h2><p>Converts between DICOM data and the DICOM JSON Model. Supports stream conversion of DICOM Part 10 data to DICOM JSON with very low memory usage.</p><p>Features an optional extension to the DICOM JSON Model that allows for the storage of encapsulated pixel data.</p><p>More details <a href="./libraries/dcmfx-json">here</a>.</p><h2 id="dcmfx-pixel-data" tabindex="-1"><code>dcmfx_pixel_data</code> <a class="header-anchor" href="#dcmfx-pixel-data" aria-label="Permalink to &quot;`dcmfx_pixel_data`&quot;">​</a></h2><p>Extracts frames of pixel data from a DICOM data set.</p><p>Note that decoding or decompression of the pixel data is not yet supported.</p><p>More details <a href="./libraries/dcmfx-pixel-data">here</a>.</p><h2 id="dcmfx-anonymize" tabindex="-1"><code>dcmfx_anonymize</code> <a class="header-anchor" href="#dcmfx-anonymize" aria-label="Permalink to &quot;`dcmfx_anonymize`&quot;">​</a></h2><p>Anonymizes the data elements in a DICOM data set or stream of DICOM Part 10 data.</p><p>More details <a href="./libraries/dcmfx-anonymize">here</a>.</p>',20)]))}const h=a(i,[["render",s]]);export{p as __pageData,h as default};
